public final class Order {
    private final List<Item> items;
    private final Address shippingAddress;
    private final PaymentMethod payment;
    private final String couponCode;
    private final boolean giftWrap;
    private final String giftMessage;
    private final boolean insurance;
    private final String deliveryNotes;
    private final double total;  // COMPUTED

    private Order(Builder b) { /* copy from builder */ }

    public static class Builder {
        // All via setters -- no constructor params
        private List<Item> items;
        private Address shippingAddress;
        private PaymentMethod payment;
        private String couponCode = null;
        private boolean giftWrap = false;
        private String giftMessage = null;
        private boolean insurance = false;
        private String deliveryNotes = null;

        public Builder items(List<Item> i) { this.items = i; return this; }
        public Builder shippingAddress(Address a) { this.shippingAddress = a; return this; }
        // ... more setters ...

        public Order build() {
            if (items == null || items.isEmpty())
                throw new IllegalStateException("Order needs items");
            if (shippingAddress == null)
                throw new IllegalStateException("Shipping address required");
            if (giftMessage != null && !giftWrap)
                throw new IllegalStateException("Gift message requires gift wrap");
            return new Order(this);
        }
    }
}

public Notification build() {
    if (title == null) throw new IllegalStateException("Title required");
    if (body == null) throw new IllegalStateException("Body required");
    if (channel == null) throw new IllegalStateException("Channel required");

    // Channel-specific constraints
    if (channel == Channel.SMS) {
        if (image != null) throw new IllegalStateException("SMS doesn't support images");
        if (!actionButtons.isEmpty()) throw new IllegalStateException("SMS doesn't support buttons");
        if (body.length() > 160) throw new IllegalStateException("SMS body max 160 chars");
    }

    // Button limit
    if (actionButtons.size() > 3)
        throw new IllegalStateException("Max 3 action buttons");

    // Time validation
    if (expiresAt != null && scheduledAt != null && expiresAt.isBefore(scheduledAt))
        throw new IllegalStateException("Expiry must be after schedule time");

    return new Notification(this);
}
